/**
 * Fluid Systems Studio — PR78 engine validation harness (FS2).
 *
 * Standalone gate runner modeled on tools/validation/welltest: labeled
 * CASES, per-check tolerances stated inline, exit 0 only on full pass.
 * Run from the repo root:
 *
 *   node tools/validation/fluidstudio/run-validation.mjs
 *
 * Prerequisite: goldens generated by the independent Python oracle
 * (python3 tools/validation/fluidstudio/genfixtures.py), committed at
 * src/utils/fluidstudio/eos/__tests__/goldens.json.
 *
 * CASE 1  BIP table vs the oracle's independent transcription of
 *           Monograph 20 Table 4-2 (typo on either side fails loudly)
 * CASE 2  Z roots + lowest-Gibbs selection vs the oracle, whose cubic is
 *           solved by bracketed bisection between the analytic extrema
 *           (the engine uses Cardano + Newton polish)
 * CASE 3  ln(phi) vs the oracle's residual-Helmholtz quadrature route
 *           (numerical volume integration of dP/dn_i cross-validates the
 *           engine's closed-form fugacity expression end to end)
 * CASE 4  Peneloux-translated molar volumes and densities vs the oracle
 * CASE 5  purePsat (fugacity-equality successive substitution) vs the
 *           oracle's Maxwell equal-area construction
 * CASE 6  NIST measured vapor pressures (normal boiling points, CO2 at
 *           0 degC) + the omega-definition identity at Tr = 0.7
 * CASE 7  Analytic identity gates: ideal-gas limit, cubic residual at
 *           the chosen root, split invariance, Peneloux leaving
 *           equilibrium quantities untouched
 * CASE 8  FS3 Rachford-Rice: binary closed form, root residual +
 *           unit-sum + material balance, negative-flash root, null when
 *           K does not straddle 1
 * CASE 9  FS3 stability + flashPT vs the plain-SS oracle flash grid
 *           (oracle: no GDEM, bisection-only RR, bisection cubic; every
 *           two-phase golden sealed by quadrature fugacity equality at
 *           generation time)
 * CASE 10 FS3 convergence identities on live flash results: isofugacity,
 *           material balance, K = y/x = phiL/phiV
 * CASE 11 FS3 low-pressure K-value limits anchored to the NIST-gated
 *           Psat: plain Raoult for the heavy component, Lewis-rule
 *           phiSat correction for the volatile one
 * CASE 12 Published literature flash fixtures (Whitson Monograph 20 /
 *           Ahmed EOS & PVT Analysis) - armed only when book-verified
 *           data is committed to literature-fixtures.json
 * CASE 13 FS4 C7+ characterization vs the oracle's second transcription
 *           of Soreide/Kesler-Lee/Lee-Kesler/Edmister/Jhaveri-Youngren/
 *           LBC-Vc/Firoozabadi/Chueh-Prausnitz, plus pure-n-alkane
 *           recovery bands anchored to NIST boiling points and the
 *           committed GPSA specific gravities
 * CASE 14 FS4 characterized-fluid flash grid vs the plain-SS oracle
 *           (pseudo built by each side's own correlation transcription)
 * CASE 15 FS4 phase boundaries / envelope vs the oracle's stability-
 *           bisection route, plus the near-pure-binary Psat identity
 *           and inside/outside flash consistency at the boundary
 * CASE 16 FS4 LBC viscosity + Weinaug-Katz IFT vs the oracle
 *           transcription, NIST dilute-gas viscosity anchors, and
 *           identity gates (pure-component mixing collapse, zero IFT
 *           for identical phases)
 * CASE 17 Coats & Smart SPE 11197 literature fixtures - armed only when
 *           paper-verified data is committed to literature-fixtures.json
 */

import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';

import {
  mixtureFromKeys, phaseProps, purePsat,
} from '../../../src/utils/fluidstudio/eos/pr78.js';
import {
  solveRachfordRice, stabilityTest, flashPT,
} from '../../../src/utils/fluidstudio/eos/flash.js';
import { COMPONENTS } from '../../../src/utils/fluidstudio/eos/components.js';
import { KtoR, degFtoR } from '../../../src/utils/fluidstudio/eos/units.js';
import {
  soreideTbR, keslerLeeTcR, keslerLeePcPsia, leeKeslerOmega, edmisterOmega,
  jhaveriYoungrenShift, lbcVcC7PlusFt3, firoozabadiParachor, chuehPrausnitzBip,
  characterizePlusFraction, mixtureWithPlusFraction,
} from '../../../src/utils/fluidstudio/eos/characterization.js';
import { phaseBoundaries, saturationPressure } from '../../../src/utils/fluidstudio/eos/envelope.js';
import {
  lbcViscosity, diluteComponentViscosity, diluteMixtureViscosity, weinaugKatzIFT,
} from '../../../src/utils/fluidstudio/eos/transport.js';

const here = path.dirname(fileURLToPath(import.meta.url));
const testsDir = path.join(here, '../../../src/utils/fluidstudio/eos/__tests__');
const goldens = JSON.parse(fs.readFileSync(path.join(testsDir, 'goldens.json'), 'utf8'));
const nist = JSON.parse(fs.readFileSync(path.join(testsDir, 'nistVaporPressure.json'), 'utf8'));

const KPA_PER_PSIA = 6.894757;

let passed = 0;
let failed = 0;

const check = (name, actual, expected, relTol, unit = '') => {
  const err = Math.abs(actual - expected) / Math.max(Math.abs(expected), 1e-300);
  const ok = Number.isFinite(actual) && err <= relTol;
  console.log(`  ${ok ? 'PASS' : 'FAIL'}  ${name}: ${actual}${unit ? ` ${unit}` : ''} vs ${expected}${unit ? ` ${unit}` : ''} (rel err ${err.toExponential(2)}, tol ${relTol})`);
  if (ok) passed += 1; else failed += 1;
};

const checkAbs = (name, actual, expected, absTol, unit = '') => {
  const err = Math.abs(actual - expected);
  const ok = Number.isFinite(actual) && err <= absTol;
  console.log(`  ${ok ? 'PASS' : 'FAIL'}  ${name}: ${actual}${unit ? ` ${unit}` : ''} vs ${expected}${unit ? ` ${unit}` : ''} (abs err ${err.toExponential(2)}, tol ${absTol})`);
  if (ok) passed += 1; else failed += 1;
};

const banner = (title) => console.log(`\n=== ${title} ===`);

const worstReport = (label, worst) => {
  const ok = worst.err <= worst.tol;
  console.log(`  ${ok ? 'PASS' : 'FAIL'}  ${label}: worst ${worst.name} err ${worst.err.toExponential(2)} (tol ${worst.tol})`);
  if (ok) passed += 1; else failed += 1;
};

// ---------------------------------------------------------------------------
banner('CASE 1: BIP table vs oracle transcription of Monograph 20 Table 4-2');
{
  const mix = mixtureFromKeys(goldens.bipKeys);
  let maxDiff = 0;
  for (let i = 0; i < mix.bip.length; i += 1) {
    for (let j = 0; j < mix.bip.length; j += 1) {
      maxDiff = Math.max(maxDiff, Math.abs(mix.bip[i][j] - goldens.bipMatrix[i][j]));
    }
  }
  checkAbs('buildBipMatrix identical to oracle table', maxDiff, 0, 0);
}

// ---------------------------------------------------------------------------
banner('CASE 2: Z roots + lowest-Gibbs selection vs bisection-route oracle');
{
  const worstZ = { name: '', err: 0, tol: 1e-10 };
  const worstRoot = { name: '', err: 0, tol: 1e-9 };
  let rootCountMismatch = 0;
  let threeRootStates = 0;
  for (const m of goldens.mixtures) {
    const mix = mixtureFromKeys(m.keys);
    for (const st of m.states) {
      const props = phaseProps(mix, m.x, degFtoR(st.tF), st.pPsia);
      const label = `${m.name} ${st.tF}F/${st.pPsia}psia`;
      if (props.roots.length !== st.roots.length) rootCountMismatch += 1;
      if (st.roots.length === 3) threeRootStates += 1;
      props.roots.forEach((z, i) => {
        const err = Math.abs(z - st.roots[i]) / Math.max(Math.abs(st.roots[i]), 1e-300);
        if (err > worstRoot.err) Object.assign(worstRoot, { name: `${label} root ${i}`, err });
      });
      const errZ = Math.abs(props.zFactor - st.z) / st.z;
      if (errZ > worstZ.err) Object.assign(worstZ, { name: label, err: errZ });
    }
  }
  checkAbs('root-count mismatches across grid', rootCountMismatch, 0, 0);
  checkAbs('three-root (selection-exercising) states in grid >= 4', Math.max(0, 4 - threeRootStates), 0, 0);
  worstReport('all real roots vs oracle', worstRoot);
  worstReport('chosen Z (lowest Gibbs) vs oracle selection', worstZ);
}

// ---------------------------------------------------------------------------
banner('CASE 3: ln(phi) vs residual-Helmholtz quadrature oracle');
{
  const worst = { name: '', err: 0, tol: 1e-8 };
  for (const m of goldens.mixtures) {
    const mix = mixtureFromKeys(m.keys);
    for (const st of m.states) {
      const props = phaseProps(mix, m.x, degFtoR(st.tF), st.pPsia);
      props.lnPhi.forEach((lp, i) => {
        const err = Math.abs(lp - st.lnPhi[i]);
        if (err > worst.err) Object.assign(worst, { name: `${m.name} ${st.tF}F/${st.pPsia}psia ${m.keys[i]}`, err });
      });
    }
  }
  worstReport('closed-form lnPhi vs numeric-integration oracle (abs)', worst);
}

// ---------------------------------------------------------------------------
banner('CASE 4: Peneloux molar volumes and densities vs oracle');
{
  const worstV = { name: '', err: 0, tol: 1e-9 };
  const worstRho = { name: '', err: 0, tol: 1e-9 };
  for (const m of goldens.mixtures) {
    const mix = mixtureFromKeys(m.keys);
    for (const st of m.states) {
      const props = phaseProps(mix, m.x, degFtoR(st.tF), st.pPsia);
      const label = `${m.name} ${st.tF}F/${st.pPsia}psia`;
      const errV = Math.abs(props.molarVolume - st.molarVolume) / Math.abs(st.molarVolume);
      const errRho = Math.abs(props.density - st.density) / st.density;
      if (errV > worstV.err) Object.assign(worstV, { name: label, err: errV });
      if (errRho > worstRho.err) Object.assign(worstRho, { name: label, err: errRho });
    }
  }
  worstReport('translated molar volume', worstV);
  worstReport('density', worstRho);
}

// ---------------------------------------------------------------------------
banner('CASE 5: purePsat successive substitution vs Maxwell equal-area oracle');
{
  const worst = { name: '', err: 0, tol: 1e-7 };
  for (const row of goldens.purePsat) {
    const psat = purePsat(COMPONENTS[row.key], row.tR);
    const err = Math.abs(psat - row.psatPsia) / row.psatPsia;
    if (err > worst.err) Object.assign(worst, { name: `${row.key} at ${row.tR.toFixed(1)}R`, err });
  }
  worstReport(`fugacity route vs equal-area route (${goldens.purePsat.length} points)`, worst);
}

// ---------------------------------------------------------------------------
banner('CASE 6: NIST measured vapor pressures + omega definition');
for (const pt of nist.points) {
  const psat = purePsat(COMPONENTS[pt.key], KtoR(pt.tK));
  check(`${pt.key} at ${pt.tK} K (${pt.note})`, psat, pt.pKPa / KPA_PER_PSIA, pt.relTol, 'psia');
}
{
  let worst = { name: '', err: 0, tol: 0.02 };
  for (const key of Object.keys(COMPONENTS)) {
    const c = COMPONENTS[key];
    const psat = purePsat(c, 0.7 * c.tcR);
    const err = Math.abs(-Math.log10(psat / c.pcPsia) - 1 - c.omega);
    if (err > worst.err) worst = { name: key, err, tol: worst.tol };
  }
  worstReport('omega recovered from Psat(0.7 Tc) (abs, all components)', worst);
}

// ---------------------------------------------------------------------------
banner('CASE 7: analytic identity gates');
{
  const mix = mixtureFromKeys(['C1', 'CO2', 'nC5']);
  const x = [0.6, 0.1, 0.3];
  const tR = degFtoR(180);

  const low = phaseProps(mix, x, tR, 0.01);
  checkAbs('ideal-gas limit Z(P=0.01 psia)', low.zFactor, 1, 1e-4);

  const mid = phaseProps(mix, x, tR, 1000);
  const { A, B, zFactor } = mid;
  const res = zFactor ** 3 - (1 - B) * zFactor ** 2
    + (A - 3 * B * B - 2 * B) * zFactor - (A * B - B * B - B ** 3);
  checkAbs('cubic residual at chosen root', res, 0, 1e-12);

  const pure = phaseProps(mixtureFromKeys(['C3']), [1], tR, 300);
  const split = phaseProps(
    mixtureFromKeys(['C3', 'C3b'], { C3b: { ...COMPONENTS.C3 } }),
    [0.35, 0.65], tR, 300,
  );
  checkAbs('split invariance: Z unchanged when a component is duplicated', split.zFactor, pure.zFactor, 1e-13);
  checkAbs('split invariance: lnPhi unchanged', split.lnPhi[0], pure.lnPhi[0], 1e-12);

  const shifted = phaseProps(mixtureFromKeys(['C1', 'nC5']), [0.4, 0.6], tR, 500);
  const zeroed = mixtureFromKeys(['C1', 'nC5']);
  zeroed.comps = zeroed.comps.map((c) => ({ ...c, shift: 0 }));
  const unshifted = phaseProps(zeroed, [0.4, 0.6], tR, 500);
  checkAbs('Peneloux leaves zFactor untouched', shifted.zFactor, unshifted.zFactor, 0);
  checkAbs('Peneloux leaves lnPhi untouched', shifted.lnPhi[1], unshifted.lnPhi[1], 0);
  // c = sum x_i s_i b_i with b_i = OMEGA_B R Tc / Pc computed right here
  const cExpected = [['C1', 0.4], ['nC5', 0.6]].reduce((s, [k, xi]) => {
    const c = COMPONENTS[k];
    return s + xi * c.shift * ((0.077796074 * 10.7316 * c.tcR) / c.pcPsia);
  }, 0);
  checkAbs('Peneloux correction equals sum x_i s_i b_i', shifted.molarVolumeEos - shifted.molarVolume, cExpected, 1e-12);
}

// ---------------------------------------------------------------------------
banner('CASE 8: Rachford-Rice identities');
{
  const z2 = [0.35, 0.65];
  const K2 = [23.9977, 0.5573];
  const analytic = -(z2[0] * (K2[0] - 1) + z2[1] * (K2[1] - 1)) / ((K2[0] - 1) * (K2[1] - 1));
  checkAbs('binary closed-form beta', solveRachfordRice(z2, K2).beta, analytic, 1e-12);

  const rr = solveRachfordRice([0.1, 0.25, 0.4, 0.25], [8, 2.2, 0.7, 0.05]);
  checkAbs('quaternary g(beta) residual', rr.residual, 0, 1e-12);
  checkAbs('x sums to 1', rr.x.reduce((a, b) => a + b, 0), 1, 1e-12);
  checkAbs('y sums to 1', rr.y.reduce((a, b) => a + b, 0), 1, 1e-12);

  const neg = solveRachfordRice([0.1, 0.9], [1.05, 0.99]);
  checkAbs('negative-flash root below 0 with zero residual', Math.min(neg.beta, 0), neg.beta, 0);
  checkAbs('negative-flash residual', neg.residual, 0, 1e-12);
  checkAbs('null when K one-sided', solveRachfordRice([0.5, 0.5], [2, 1.1]) === null ? 0 : 1, 0, 0);
}

// ---------------------------------------------------------------------------
banner('CASE 9: stability + flashPT vs plain-SS oracle flash grid');
{
  let phaseMismatch = 0;
  let stabilityMismatch = 0;
  let twoPhase = 0;
  const worstBeta = { name: '', err: 0, tol: 1e-9 };
  const worstComp = { name: '', err: 0, tol: 1e-9 };
  const worstK = { name: '', err: 0, tol: 1e-8 };
  const worstRho = { name: '', err: 0, tol: 1e-8 };
  for (const m of goldens.flash) {
    const mix = mixtureFromKeys(m.keys);
    for (const st of m.states) {
      const label = `${m.name} ${st.tF}F/${st.pPsia}psia`;
      const res = flashPT(mix, m.x, degFtoR(st.tF), st.pPsia);
      if (res.phases !== st.phases) phaseMismatch += 1;
      if (st.phases !== 2) continue;
      twoPhase += 1;
      if (stabilityTest(mix, m.x, degFtoR(st.tF), st.pPsia).stable) stabilityMismatch += 1;
      const eb = Math.abs(res.beta - st.beta);
      if (eb > worstBeta.err) Object.assign(worstBeta, { name: label, err: eb });
      st.x.forEach((v, i) => {
        const e = Math.max(Math.abs(res.x[i] - v), Math.abs(res.y[i] - st.y[i]));
        if (e > worstComp.err) Object.assign(worstComp, { name: `${label} ${m.keys[i]}`, err: e });
        const ek = Math.abs(res.K[i] - st.K[i]) / st.K[i];
        if (ek > worstK.err) Object.assign(worstK, { name: `${label} ${m.keys[i]}`, err: ek });
      });
      const er = Math.max(
        Math.abs(res.liquid.density - st.rhoL) / st.rhoL,
        Math.abs(res.vapor.density - st.rhoV) / st.rhoV,
      );
      if (er > worstRho.err) Object.assign(worstRho, { name: label, err: er });
    }
  }
  checkAbs('phase-count mismatches across grid', phaseMismatch, 0, 0);
  checkAbs('stability disagreements on two-phase states', stabilityMismatch, 0, 0);
  checkAbs('two-phase states exercised >= 8', Math.max(0, 8 - twoPhase), 0, 0);
  worstReport('beta vs oracle (abs)', worstBeta);
  worstReport('x/y vs oracle (abs)', worstComp);
  worstReport('K vs oracle (rel)', worstK);
  worstReport('phase densities vs oracle (rel)', worstRho);
}

// ---------------------------------------------------------------------------
banner('CASE 10: flash convergence identities (live results)');
{
  const worstFug = { name: '', err: 0, tol: 1e-9 };
  const worstMb = { name: '', err: 0, tol: 1e-12 };
  for (const m of goldens.flash) {
    const mix = mixtureFromKeys(m.keys);
    for (const st of m.states.filter((s) => s.phases === 2)) {
      const label = `${m.name} ${st.tF}F/${st.pPsia}psia`;
      const res = flashPT(mix, m.x, degFtoR(st.tF), st.pPsia);
      res.liquid.fugacityPsia.forEach((f, i) => {
        const e = Math.abs(f - res.vapor.fugacityPsia[i]) / f;
        if (e > worstFug.err) Object.assign(worstFug, { name: `${label} ${m.keys[i]}`, err: e });
        const mb = Math.abs((1 - res.beta) * res.x[i] + res.beta * res.y[i] - m.x[i]);
        if (mb > worstMb.err) Object.assign(worstMb, { name: `${label} ${m.keys[i]}`, err: mb });
      });
    }
  }
  worstReport('isofugacity f_L = f_V (rel)', worstFug);
  worstReport('material balance (1-b)x + by = z (abs)', worstMb);
  const seals = goldens.flash.flatMap((m) => m.states).map((s) => s.fugacitySeal).filter((v) => v !== undefined);
  const worstSeal = Math.max(...seals);
  checkAbs(`goldens quadrature fugacity seal (${seals.length} states, generation-time)`, worstSeal, 0, 1e-6);
}

// ---------------------------------------------------------------------------
banner('CASE 11: low-pressure K limits anchored to NIST-gated Psat');
{
  const mix = mixtureFromKeys(['C3', 'nC5']);
  const tR = degFtoR(100);
  const p = 20;
  const res = flashPT(mix, [0.1, 0.9], tR, p);
  checkAbs('C3/nC5 100F/20psia is two-phase', res.phases, 2, 0);
  check('Raoult limit, heavy: K_nC5 vs Psat/P', res.K[1], purePsat(COMPONENTS.nC5, tR) / p, 0.02);
  const psatC3 = purePsat(COMPONENTS.C3, tR);
  const satVap = phaseProps(mixtureFromKeys(['C3']), [1], tR, psatC3, { root: 'max' });
  check('Lewis rule, light: K_C3 P/Psat vs phiSat', (res.K[0] * p) / psatC3, Math.exp(satVap.lnPhi[0]), 0.03);
}

// ---------------------------------------------------------------------------
banner('CASE 12: published literature flash fixtures');
{
  const lit = JSON.parse(fs.readFileSync(path.join(here, 'literature-fixtures.json'), 'utf8'));
  if (!lit.flashes.length) {
    console.log('  SKIP  unarmed: commit book-verified data to literature-fixtures.json to gate');
  }
  for (const fx of lit.flashes) {
    const mix = mixtureFromKeys(fx.keys);
    const res = flashPT(mix, fx.z, degFtoR(fx.tF), fx.pPsia);
    checkAbs(`${fx.citation}: two-phase`, res.phases, 2, 0);
    if (res.phases !== 2) continue;
    if (fx.expected.beta !== undefined) {
      check(`${fx.citation}: beta`, res.beta, fx.expected.beta, fx.tolerances.beta);
    }
    (fx.expected.K || []).forEach((k, i) => {
      check(`${fx.citation}: K ${fx.keys[i]}`, res.K[i], k, fx.tolerances.K);
    });
  }
}

// ---------------------------------------------------------------------------
banner('CASE 13: C7+ characterization vs oracle transcription + n-alkane recovery');
{
  const worst = { name: '', err: 0, tol: 1e-12 };
  for (const row of goldens.characterization) {
    const input = { mw: row.mw, sg: row.sg };
    if (row.tbInput !== undefined) input.tbR = row.tbInput;
    const ch = characterizePlusFraction(input);
    const pairs = [
      ['tbR', ch.meta.tbR, row.tbR],
      ['tcR', ch.comp.tcR, row.tcR],
      ['pcPsia', ch.comp.pcPsia, row.pcPsia],
      ['omega', ch.comp.omega, row.omega],
      ['omegaEdmister', edmisterOmega(ch.meta.tbR, ch.comp.tcR, ch.comp.pcPsia), row.omegaEdmister],
      ['vc', ch.comp.vcFt3PerLbmol, row.vcFt3PerLbmol],
      ['parachor', ch.comp.parachor, row.parachor],
      ['shift', ch.comp.shift, row.shift],
      ['bipC1', ch.bip.C1, row.bipC1],
    ];
    for (const [label, a, b] of pairs) {
      const err = Math.abs(a - b) / Math.max(Math.abs(b), 1e-300);
      if (err > worst.err) Object.assign(worst, { name: `mw=${row.mw} sg=${row.sg} ${label}`, err });
    }
  }
  worstReport(`characterization grid vs oracle (${goldens.characterization.length} points x 9 fields, rel)`, worst);

  const charRef = JSON.parse(fs.readFileSync(path.join(testsDir, 'characterizationReference.json'), 'utf8'));
  for (const anchor of charRef.alkaneRecovery) {
    const lib = COMPONENTS[anchor.key];
    const tbR = KtoR(nist.points.find((p) => p.key === anchor.key).tK);
    const tc = keslerLeeTcR(tbR, anchor.sg);
    const pc = keslerLeePcPsia(tbR, anchor.sg);
    const om = leeKeslerOmega(tbR, tc, pc, anchor.sg);
    check(`${anchor.key} Kesler-Lee Tc recovery (NIST Tb + GPSA SG)`, tc, lib.tcR, anchor.tcRelTol, 'degR');
    check(`${anchor.key} Kesler-Lee Pc recovery`, pc, lib.pcPsia, anchor.pcRelTol, 'psia');
    checkAbs(`${anchor.key} Lee-Kesler omega recovery`, om, lib.omega, anchor.omegaAbsTol);
  }
  for (const smoke of charRef.soreideSmoke) {
    const tbR = KtoR(nist.points.find((p) => p.key === smoke.key).tK);
    check(`${smoke.key} Soreide Tb smoke (out-of-range edge, typo guard)`, soreideTbR(COMPONENTS[smoke.key].mw, smoke.sg), tbR, smoke.relTol, 'degR');
  }

  // spot identities on the correlation set itself
  checkAbs('Chueh-Prausnitz kij(v, v) = 0', chuehPrausnitzBip(4.0, 4.0), 0, 0);
  const s150 = jhaveriYoungrenShift(150);
  checkAbs('Jhaveri-Youngren paraffin s(150) = 1 - 2.258/150^0.1823', s150, 1 - 2.258 / 150 ** 0.1823, 0);
  checkAbs('Firoozabadi parachor at MW 150', firoozabadiParachor(150), -11.4 + 3.23 * 150 - 0.0022 * 150 * 150, 0);
  checkAbs('LBC Vc7+ at MW 190 / SG 0.84', lbcVcC7PlusFt3(190, 0.84), 21.573 + 0.015122 * 190 - 27.656 * 0.84 + 0.070615 * 190 * 0.84, 0);
}

// ---------------------------------------------------------------------------
banner('CASE 14: characterized-fluid flash grid vs plain-SS oracle');
{
  let phaseMismatch = 0;
  let twoPhase = 0;
  const worstBeta = { name: '', err: 0, tol: 1e-8 };
  const worstComp = { name: '', err: 0, tol: 1e-8 };
  const worstRho = { name: '', err: 0, tol: 1e-7 };
  for (const m of goldens.flashC7) {
    const mix = mixtureWithPlusFraction(m.keys, m.plus);
    for (const st of m.states) {
      const label = `${m.name} ${st.tF}F/${st.pPsia}psia`;
      const res = flashPT(mix, m.x, degFtoR(st.tF), st.pPsia);
      if (res.phases !== st.phases) phaseMismatch += 1;
      if (st.phases !== 2 || res.phases !== 2) continue;
      twoPhase += 1;
      const eb = Math.abs(res.beta - st.beta);
      if (eb > worstBeta.err) Object.assign(worstBeta, { name: label, err: eb });
      st.x.forEach((v, i) => {
        const e = Math.max(Math.abs(res.x[i] - v), Math.abs(res.y[i] - st.y[i]));
        if (e > worstComp.err) Object.assign(worstComp, { name: label, err: e });
      });
      const er = Math.max(
        Math.abs(res.liquid.density - st.rhoL) / st.rhoL,
        Math.abs(res.vapor.density - st.rhoV) / st.rhoV,
      );
      if (er > worstRho.err) Object.assign(worstRho, { name: label, err: er });
    }
  }
  checkAbs('phase-count mismatches on characterized grid', phaseMismatch, 0, 0);
  checkAbs('two-phase characterized states exercised >= 2', Math.max(0, 2 - twoPhase), 0, 0);
  worstReport('beta vs oracle (abs)', worstBeta);
  worstReport('x/y vs oracle (abs)', worstComp);
  worstReport('phase densities vs oracle (rel)', worstRho);
}

// ---------------------------------------------------------------------------
banner('CASE 15: phase boundaries / envelope vs oracle stability bisection');
{
  let countMismatch = 0;
  let kindMismatch = 0;
  let boundaryCount = 0;
  const worstP = { name: '', err: 0, tol: 2e-4 };
  for (const env of goldens.envelopes) {
    const mix = env.plus ? mixtureWithPlusFraction(env.keys, env.plus) : mixtureFromKeys(env.keys);
    for (const st of env.states) {
      const label = `${env.name} ${st.tF}F`;
      const bounds = phaseBoundaries(mix, env.x, degFtoR(st.tF));
      if (bounds.length !== st.boundaries.length) {
        countMismatch += 1;
        continue;
      }
      st.boundaries.forEach((ob, i) => {
        boundaryCount += 1;
        if (bounds[i].kind !== ob.kind) kindMismatch += 1;
        const err = Math.abs(bounds[i].pPsia - ob.pPsia) / ob.pPsia;
        if (err > worstP.err) Object.assign(worstP, { name: `${label} ${ob.kind}`, err });
      });
    }
  }
  checkAbs('boundary-count mismatches across envelope grid', countMismatch, 0, 0);
  checkAbs('boundary-kind mismatches', kindMismatch, 0, 0);
  checkAbs('boundaries exercised >= 10', Math.max(0, 10 - boundaryCount), 0, 0);
  worstReport('boundary pressures vs oracle (rel)', worstP);

  // Raoult identity: for the near-ideal equimolar C3/nC4 the bubble
  // point sits within a few percent of sum z_i Psat_i, both Psat values
  // NIST-anchored by CASE 6 (the scan cannot see the razor-thin
  // two-phase window of a near-pure fluid, so the mixture is equimolar)
  const tR = degFtoR(100);
  const mixC3 = mixtureFromKeys(['C3', 'nC4']);
  const sat = saturationPressure(mixC3, [0.5, 0.5], tR, { pMaxPsia: 600 });
  const raoult = 0.5 * purePsat(COMPONENTS.C3, tR) + 0.5 * purePsat(COMPONENTS.nC4, tR);
  checkAbs('equimolar C3/nC4 top boundary is a bubble point', sat.kind === 'bubble' ? 0 : 1, 0, 0);
  check('equimolar C3/nC4 bubble point vs Raoult from NIST-gated Psat', sat.pPsia, raoult, 0.06, 'psia');

  // inside/outside consistency at a characterized-oil bubble point
  const oilEnv = goldens.envelopes.find((e) => e.name === 'char-oil');
  const oilMix = mixtureWithPlusFraction(oilEnv.keys, oilEnv.plus);
  const bub = oilEnv.states[1].boundaries[0];
  const tOil = degFtoR(oilEnv.states[1].tF);
  const inside = flashPT(oilMix, oilEnv.x, tOil, bub.pPsia - 25);
  const outside = flashPT(oilMix, oilEnv.x, tOil, bub.pPsia + 25);
  checkAbs('flash 25 psia inside bubble point: 2 phases', inside.phases, 2, 0);
  checkAbs('flash 25 psia outside bubble point: 1 phase', outside.phases, 1, 0);
  checkAbs('vapor fraction just inside bubble point < 0.05', Math.max(0, inside.phases === 2 ? inside.beta - 0.05 : 1), 0, 0);
}

// ---------------------------------------------------------------------------
banner('CASE 16: LBC viscosity + Weinaug-Katz IFT vs oracle + NIST anchors');
{
  const charRef = JSON.parse(fs.readFileSync(path.join(testsDir, 'characterizationReference.json'), 'utf8'));
  const worstMu = { name: '', err: 0, tol: 1e-6 };
  const worstIft = { name: '', err: 0, tol: 1e-6 };
  for (const tr of goldens.transport) {
    const flashSrc = (goldens.flash.find((f) => f.name === tr.name) || goldens.flashC7.find((f) => f.name === tr.name));
    const charSrc = goldens.flashC7.find((f) => f.name === tr.name);
    const mix = charSrc ? mixtureWithPlusFraction(charSrc.keys, charSrc.plus) : mixtureFromKeys(flashSrc.keys);
    for (const st of tr.states) {
      const label = `${tr.name} ${st.tF}F/${st.pPsia}psia`;
      const res = flashPT(mix, flashSrc.x, degFtoR(st.tF), st.pPsia);
      const muL = lbcViscosity(mix, res.x, degFtoR(st.tF), res.liquid).viscosityCp;
      const muV = lbcViscosity(mix, res.y, degFtoR(st.tF), res.vapor).viscosityCp;
      const ift = weinaugKatzIFT(mix, res.x, res.y, res.liquid, res.vapor).iftDynPerCm;
      const eMu = Math.max(Math.abs(muL - st.muL) / st.muL, Math.abs(muV - st.muV) / st.muV);
      if (eMu > worstMu.err) Object.assign(worstMu, { name: label, err: eMu });
      const eI = Math.abs(ift - st.iftDynPerCm) / st.iftDynPerCm;
      if (eI > worstIft.err) Object.assign(worstIft, { name: label, err: eI });
    }
  }
  worstReport('phase viscosities vs oracle (rel)', worstMu);
  worstReport('IFT vs oracle (rel)', worstIft);

  for (const anchor of charRef.diluteViscosity) {
    const comp = COMPONENTS[anchor.key];
    const tR = KtoR(anchor.tK);
    const mix1 = mixtureFromKeys([anchor.key]);
    const props = phaseProps(mix1, [1], tR, 14.696);
    const mu = lbcViscosity(mix1, [1], tR, props).viscosityCp;
    check(`${anchor.key} LBC at 1 atm / ${anchor.tK} K vs NIST`, mu, anchor.muCp, anchor.relTol, 'cP');
  }

  const tR = degFtoR(150);
  const mixPair = mixtureFromKeys(['C1', 'C3']);
  checkAbs(
    'Herning-Zipperer collapses to Stiel-Thodos for a pure component',
    diluteMixtureViscosity(mixtureFromKeys(['C3']), [1], tR),
    diluteComponentViscosity(COMPONENTS.C3, tR),
    0,
  );
  const st150 = phaseProps(mixPair, [0.5, 0.5], tR, 500);
  const iftSame = weinaugKatzIFT(mixPair, [0.5, 0.5], [0.5, 0.5], st150, st150);
  checkAbs('Weinaug-Katz IFT of identical phases = 0', iftSame.iftDynPerCm, 0, 0);
}

